public XSSFWorkbook createTakePageSheet(String title, List<PanBanExcleDetail> list) throws IOException {
    // 创建工作簿
    XSSFWorkbook workbook = new XSSFWorkbook();

    // 创建表
    Sheet sheet = workbook.createSheet(title);

    // 创建标题行
