    Cell headerCell0 = headerRow.createCell(0);
    headerCell0.setCellValue("Sqsj"); 
    Cell headerCell1 = headerRow.createCell(1);
    headerCell1.setCellValue("Sqjx");
    Cell headerCell2 = headerRow.createCell(2);
    headerCell2.setCellValue("Zjcx");
    Cell headerCell3 = headerRow.createCell(3);
    headerCell3.setCellValue("Sfzmmc");
    Cell headerCell4 = headerRow.createCell(4);
    headerCell4.setCellValue("Xm");
    Cell headerCell5 = headerRow.createCell(5);
    headerCell5.setCellValue("Sfzmhm");
    Cell headerCell6 = headerRow.createCell(6);
    headerCell6.setCellValue("Yjxmc");
    Cell headerCell7 = headerRow.createCell(7);
    headerCell7.setCellValue("Image");

    int rowIdx = 1;
    for (PanBanExcleDetail detail : list) {
        Row row = sheet.createRow(rowIdx++);

        row.createCell(0).setCellValue(detail.getSqsj());
        row.createCell(1).setCellValue(detail.getSqjx());
        row.createCell(2).setCellValue(detail.getZjcx());
        row.createCell(3).setCellValue(detail.getSfzmmc());
